// Playlist.getTracks() must return a defensive copy

exercises.expected_solution:
import java.util.Arrays;

class Song {
    private String name;
    public Song(String name) { this.name = name; }
    public String getName() { return name; }
}

class Playlist {
    private Song[] tracks;
    private int count;

    public Playlist() {
        this.tracks = new Song[10];
        this.count = 0;
    }

    public void addTrack(Song s) {
        if (count < tracks.length) {
            tracks[count++] = s;
        }
    }

    public Song[] getTracks() {
        return Arrays.copyOf(tracks, count);  // defensive copy!
    }

    public int getCount() { return count; }
}

public class App {
    public static void main(String[] args) {
        Playlist pl = new Playlist();
        pl.addTrack(new Song("Song A"));
        pl.addTrack(new Song("Song B"));
        pl.addTrack(new Song("Song C"));

        System.out.println("Playlist tracks: " + pl.getCount());

        Song[] copy = pl.getTracks();
        copy[0] = null;  // modify the returned copy
        copy[1] = null;

        System.out.println("After modifying returned copy: still " + pl.getCount());
    }
}

