// Build the full e-commerce system using every Module 4 pattern
// Category (immutable), Product (entity with static + encapsulation + Object methods)
// CartItem (composition), ShoppingCart (array composition)

exercises.expected_solution:
import java.util.Objects;

class Category {
    private final String name;
    private final String description;

    public Category(String name, String description) {
        this.name = name;
        this.description = description;
    }

    public String getName() { return name; }
    public String getDescription() { return description; }

    @Override
    public String toString() { return name; }
}

class Product {
    private static int nextId = 1;
    public static final double MAX_PRICE = 999999.0;

    private final int id;
    private String name;
    private double price;
    private Category category;

    public Product(String name, double price, Category category) {
        if (name == null || name.isBlank()) throw new IllegalArgumentException("Name required");
        if (price <= 0 || price > MAX_PRICE) throw new IllegalArgumentException("Invalid price");
        this.id = nextId++;
        this.name = name;
        this.price = price;
        this.category = category;
    }

    public int getId() { return id; }
    public String getName() { return name; }
    public double getPrice() { return price; }
    public Category getCategory() { return category; }

    public void setPrice(double price) {
        if (price <= 0 || price > MAX_PRICE) throw new IllegalArgumentException("Invalid price");
        this.price = price;
    }

    public double discountedPrice(double percent) {
        return price * (1 - percent / 100);
    }

    @Override
    public String toString() {
        return "Product[#" + id + " " + name + " ₹" + price + " (" + category + ")]";
    }

    @Override
    public boolean equals(Object o) {
        if (!(o instanceof Product)) return false;
        return this.id == ((Product) o).id;
    }

    @Override
    public int hashCode() { return Objects.hash(id); }
}

class CartItem {
    private Product product;
    private int quantity;

    public CartItem(Product product, int quantity) {
        this.product = product;
        this.quantity = quantity;
    }

    public double lineTotal() { return product.getPrice() * quantity; }
    public Product getProduct() { return product; }
    public int getQuantity() { return quantity; }
}

class ShoppingCart {
    private CartItem[] items;
    private int count;

    public ShoppingCart() {
        this.items = new CartItem[20];
        this.count = 0;
    }

    public void addItem(Product product, int quantity) {
        if (count < items.length) {
            items[count++] = new CartItem(product, quantity);
        }
    }

    public double cartTotal() {
        double total = 0;
        for (int i = 0; i < count; i++) total += items[i].lineTotal();
        return total;
    }

    public int countItems() { return count; }
